+/// Get the best available SIMD level as a string
+pub fn simd_level() -> &'static str {
+    #[cfg(target_arch = "x86_64")]
+    {
+        if is_avx512_available() {
+            "AVX-512"
+        } else if is_avx2_available() {
+            "AVX2"
+        } else {
